const LOGO_B64 = '';

// State
let installState = { kit: false, core: false, abat: false, serv: false, desp: false };
let resumenState = { op1: true, op2: true };
let rowCount = 0;

// Init
window.onload = () => {
  const today = new Date().toISOString().split('T')[0];
  document.getElementById('fecha').value = today;
  addRow();
  addRow();
  addRow();
};

function addRow() {
  rowCount++;
  const n = rowCount;
  const tbody = document.getElementById('itemsBody');
  const tr = document.createElement('tr');
  tr.id = 'row_' + n;
  tr.innerHTML = `
    <td class="row-num">${n}</td>
    <td><input type="text" placeholder="Ej: Taza 11oz" onchange="recalcular()"></td>
    <td><input type="text" placeholder="Ej: Cerámica" onchange="recalcular()"></td>
    <td><input type="number" min="1" placeholder="1" onchange="recalcular()"></td>
    <td><input type="number" min="0" placeholder="Precio unitario" onchange="recalcular()"></td>
    <td><button class="btn-del" onclick="delRow(${n})">✕</button></td>
  `;
  tbody.appendChild(tr);
}

function delRow(n) {
  const el = document.getElementById('row_' + n);
  if (el) el.remove();
  recalcular();
}

function toggleInst(key) {
  installState[key] = !installState[key];
  const btn = document.getElementById(key + '_toggle');
  btn.textContent = installState[key] ? 'SÍ' : 'NO';
  btn.className = 'toggle-btn ' + (installState[key] ? 'on' : 'off');
  recalcular();
}

function toggleResumen(key) {
  resumenState[key] = !resumenState[key];
  const btn = document.getElementById(key + '_toggle');
  if (btn) {
    btn.textContent = resumenState[key] ? 'ACTIVA' : 'INACTIVA';
    btn.className = 'resumen-toggle ' + (resumenState[key] ? 'on' : 'off');
  }
  recalcular();
}

function getInstTotal() {
  let total = 0;
  ['kit','core','desp'].forEach(k => {
    if (installState[k]) {
      const v = parseFloat(document.getElementById(k + '_precio').value) || 0;
      total += v;
    }
  });
  return total;
}

function getRows() {
  const rows = [];
  document.querySelectorAll('#itemsBody tr').forEach(tr => {
    const inputs = tr.querySelectorAll('input');
    if (inputs.length < 4) return;
    const desc = inputs[0].value;
    const tipo = inputs[1].value;
    const cantidad = parseFloat(inputs[2].value) || 0;
    const precioUnitario = parseFloat(inputs[3].value) || 0;
    rows.push({
      desc, tipo, cantidad, precioUnitario
    });
  });
  return rows;
}

function recalcular() {
  const rows = getRows();
  
  // Contar productos por descripción
  const productCounts = {};
  rows.forEach(r => {
    const desc = r.desc || '';
    productCounts[desc] = (productCounts[desc] || 0) + r.cantidad;
  });
  
  // Resaltar filas con descuento (usa variable CSS --highlight)
  const __cs = getComputedStyle(document.documentElement);
  const __highlight = (__cs.getPropertyValue('--highlight') || '#fff3cd').trim();
  document.querySelectorAll('#itemsBody tr').forEach(tr => {
    const inputs = tr.querySelectorAll('input');
    if (inputs.length >= 4) {
      const desc = inputs[0].value;
      const totalProductos = productCounts[desc] || 0;
      if (totalProductos >= 10) {
        tr.style.backgroundColor = __highlight; // Destacar fila con descuento
      } else {
        tr.style.backgroundColor = '';
      }
    }
  });

  // Calcular totales
  const kitV = installState.kit ? (parseFloat(document.getElementById('kit_precio').value)||0) : 0;
  const coreV = installState.core ? (parseFloat(document.getElementById('core_precio').value)||0) : 0;
  const despV = installState.desp ? (parseFloat(document.getElementById('desp_precio').value)||0) : 0;
  const opcionalesTotal = kitV + coreV + despV;

  let subProductosOriginal = 0, subProductos = 0, descuentoTotal = 0;
  rows.forEach(r => {
    const totalProductos = productCounts[r.desc || ''] || 0;
    const precioOriginal = r.precioUnitario * r.cantidad;
    subProductosOriginal += precioOriginal;
    
    let precioUnitario = r.precioUnitario;
    if (totalProductos >= 10) {
      precioUnitario = r.precioUnitario * 0.8; // Aplicar 20% descuento
      descuentoTotal += precioOriginal - (precioUnitario * r.cantidad);
    }
    subProductos += precioUnitario * r.cantidad;
  });

  const totalRaw = subProductos + opcionalesTotal;
  const fmt = v => '$' + Math.round(v).toLocaleString('es-CL');

  // Mostrar u ocultar fila de descuento
  const descuentoRow = document.getElementById('descuento-row');
  if (descuentoTotal > 0) {
    descuentoRow.style.display = '';
    document.getElementById('r1_descuento').textContent = '- ' + fmt(descuentoTotal);
    document.getElementById('r1_original').textContent = fmt(subProductosOriginal);
  } else {
    descuentoRow.style.display = 'none';
    document.getElementById('r1_original').textContent = fmt(subProductos);
  }

  document.getElementById('r1_sub').textContent = fmt(subProductos);
  document.getElementById('r1_kit').textContent = fmt(opcionalesTotal);
  document.getElementById('total1').textContent = fmt(totalRaw);
}

function limpiarForm() {
  if (!confirm('¿Limpiar todos los datos?')) return;
  ['nombre','rut','contacto','telefono','direccion'].forEach(id => document.getElementById(id).value = '');
  document.getElementById('ncotizacion').value = '1';
  document.getElementById('itemsBody').innerHTML = '';
  rowCount = 0;
  ['kit','core','desp'].forEach(k => {
    installState[k] = false;
    const btn = document.getElementById(k + '_toggle');
    if (btn) {
      btn.textContent = 'NO';
      btn.className = 'toggle-btn off';
    }
    const inp = document.getElementById(k + '_precio');
    if (inp) inp.value = '';
  });
  addRow(); addRow(); addRow();
  recalcular();
}

// (Debug helpers removed)

// ===== PDF EXPORT =====
async function exportarPDF() {
  const btn = document.querySelector('.btn-export:not(.secondary)');
  btn.textContent = '⏳ Generando...';
  btn.disabled = true;

  await new Promise(r => setTimeout(r, 100));

  try {
    const { jsPDF } = window.jspdf;
    const doc = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' });
    const W = 210, H = 297;
    const margin = 14;
    let y = 0;

    // Colors: read from CSS variables to match styles.css
    function hexToRgb(input) {
      if (!input) return [0,0,0];
      input = String(input).trim();
      if (input.startsWith('rgb')) {
        const m = input.match(/\d+/g) || [0,0,0];
        return [parseInt(m[0]), parseInt(m[1]), parseInt(m[2])];
      }
      if (input.startsWith('#')) {
        let hex = input.slice(1);
        if (hex.length === 3) hex = hex.split('').map(h=>h+h).join('');
        const num = parseInt(hex, 16);
        return [(num >> 16) & 255, (num >> 8) & 255, num & 255];
      }
      return [0,0,0];
    }
    const __cs = getComputedStyle(document.documentElement);
    // Try to read colors from useful DOM elements so PDF matches rendered UI
    function readComputedColor(selector, prop = 'backgroundColor') {
      try {
        const el = document.querySelector(selector);
        if (!el) return null;
        return getComputedStyle(el)[prop] || null;
      } catch(e) { return null; }
    }

    const brownSrc = readComputedColor('.app-header', 'backgroundColor') || __cs.getPropertyValue('--brown') || __cs.getPropertyValue('--surface') || '#1a1a1a';
    const goldSrc = __cs.getPropertyValue('--gold') || __cs.getPropertyValue('--accent-red') || '#dc143c';
    const goldLightSrc = __cs.getPropertyValue('--gold-light') || __cs.getPropertyValue('--accent-red') || '#ff6b6b';
    const creamSrc = readComputedColor('.section', 'backgroundColor') || __cs.getPropertyValue('--cream') || __cs.getPropertyValue('--bg') || '#f5f3ee';
    const grayLightSrc = __cs.getPropertyValue('--gray-light') || __cs.getPropertyValue('--border') || '#e2dfd8';

    const brown = hexToRgb(brownSrc);
    const gold = hexToRgb(goldSrc);
    const goldLight = hexToRgb(goldLightSrc);
    const cream = hexToRgb(creamSrc);
    const grayLight = hexToRgb(grayLightSrc);
    const white = [255,255,255];
    const dark = [0,0,0];

    const fmtCLP = v => {
      if (!v && v !== 0) return '';
      return '$' + Math.round(v).toLocaleString('es-CL');
    };

    // ── HEADER BAND ──
    doc.setFillColor(...brown);
    doc.rect(0, 0, W, 28, 'F');

    // Logo
    try {
      doc.addImage('img/menarquita.jpeg', 'JPEG', margin, 3, 22, 22);
    } catch(e) {}

    // Company name
    doc.setTextColor(...white);
    doc.setFontSize(20);
    doc.setFont('helvetica', 'bold');
    doc.text('Menarquita', 40, 12);
    doc.setFontSize(8);
    doc.setFont('helvetica', 'italic');
    doc.text('Personalización en sublimado y más', 40, 18);

    // Contact right side
    doc.setFontSize(7);
    doc.setFont('helvetica', 'normal');
    doc.setTextColor(...gold);
    const rightX = W - margin;
    doc.text('info@menarquita.cl ', rightX, 9, {align:'right'});
    doc.text('+56 9 2870 6208', rightX, 14, {align:'right'});
    doc.text('Talca, Chile', rightX, 19, {align:'right'});

    y = 35;

    // ── TITLE ──
    doc.setTextColor(...brown);
    doc.setFontSize(16);
    doc.setFont('helvetica', 'bold');
    const ncot = document.getElementById('ncotizacion').value || '___';
    doc.text(`C O T I Z A C I Ó N   N°  ${ncot.toString().padStart(4,'0')}`, W/2, y, {align:'center'});
    y += 3;
    doc.setDrawColor(...gold);
    doc.setLineWidth(0.8);
    doc.line(margin, y, W-margin, y);
    y += 7;

    // ── CLIENT BOX ──
    doc.setFillColor(...cream);
    doc.setDrawColor(...brown);
    doc.setLineWidth(0.4);
    doc.roundedRect(margin, y, W - margin*2, 26, 2, 2, 'FD');

    const fecha = document.getElementById('fecha').value;
    const fechaFmt = fecha ? new Date(fecha + 'T12:00:00').toLocaleDateString('es-CL', {day:'2-digit',month:'2-digit',year:'numeric'}) : '___';
    
    doc.setFontSize(8);
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(...brown);
    
    // Row 1
    const r1y = y + 7;
    doc.text('Nombre:', margin+3, r1y);
    doc.setFont('helvetica','normal'); doc.setTextColor(...dark);
    doc.text(document.getElementById('nombre').value || '', margin+20, r1y);
    
    doc.setFont('helvetica','bold'); doc.setTextColor(...brown);
    doc.text('RUT:', W/2, r1y);
    doc.setFont('helvetica','normal'); doc.setTextColor(...dark);
    doc.text(document.getElementById('rut').value || '', W/2+12, r1y);
    
    doc.setFont('helvetica','bold'); doc.setTextColor(...brown);
    doc.text('Fecha:', W-60, r1y);
    doc.setFont('helvetica','normal'); doc.setTextColor(...dark);
    doc.text(fechaFmt, W-45, r1y);

    // Row 2
    const r2y = y + 14;
    doc.setFont('helvetica','bold'); doc.setTextColor(...brown);
    doc.text('Contacto:', margin+3, r2y);
    doc.setFont('helvetica','normal'); doc.setTextColor(...dark);
    doc.text(document.getElementById('contacto').value || '', margin+22, r2y);
    
    doc.setFont('helvetica','bold'); doc.setTextColor(...brown);
    doc.text('Teléfono:', W/2, r2y);
    doc.setFont('helvetica','normal'); doc.setTextColor(...dark);
    doc.text(document.getElementById('telefono').value || '', W/2+18, r2y);

    // Row 3
    const r3y = y + 21;
    doc.setFont('helvetica','bold'); doc.setTextColor(...brown);
    doc.text('Dirección:', margin+3, r3y);
    doc.setFont('helvetica','normal'); doc.setTextColor(...dark);
    doc.text(document.getElementById('direccion').value || '', margin+22, r3y);

    y += 32;

    // ── ITEMS TABLE ──
    // Header
    const cols = [
      {label:'N°', w:8, align:'center'},
      {label:'Producto', w:50, align:'left'},
      {label:'Tipo', w:30, align:'center'},
      {label:'Cant.', w:15, align:'center'},
      {label:'Precio\nUnitario ($)', w:35, align:'center'},
    ];
    const tableW = W - margin*2;
    // Adjust widths proportionally
    const totalW = cols.reduce((s,c)=>s+c.w,0);
    cols.forEach(c => c.w = c.w/totalW*tableW);

    // Header row
    doc.setFillColor(...gold);
    doc.rect(margin, y, tableW, 10, 'F');
    
    let cx = margin;
    cols.forEach(col => {
      doc.setTextColor(...white);
      doc.setFontSize(6.5);
      doc.setFont('helvetica','bold');
      const lines = col.label.split('\n');
      lines.forEach((line, li) => {
        const ty = y + 4 + li*3.5 - (lines.length-1)*1.5;
        if (col.align === 'center') {
          doc.text(line, cx + col.w/2, ty, {align:'center'});
        } else {
          doc.text(line, cx + 2, ty);
        }
      });
      cx += col.w;
    });
    y += 10;

    // Data rows (support multiline description)
    const rows = getRows();
    const dataRows = rows.length > 0 ? rows : Array(8).fill({desc:'',tipo:'',cantidad:'',precioUnitario:''});
    const MAX_ROWS = 10;
    const displayRows = dataRows.slice(0, MAX_ROWS);
    while(displayRows.length < 8) displayRows.push({desc:'',tipo:'',cantidad:'',precioUnitario:''});

    const tableTop = y - 10; // header was drawn 10mm above current y
    let tableBodyHeight = 0;

    displayRows.forEach((row, i) => {
      // compute wrapped lines for description
      doc.setFont('helvetica','normal');
      doc.setFontSize(7.5);
      const descLines = doc.splitTextToSize(String(row.desc || ''), cols[1].w - 3);
      const lineCount = Math.max(1, descLines.length);
      const lineH = 4.5;
      const rowH = Math.max(7, lineCount * lineH);
      
      // alternate background
      if (i % 2 === 1) {
        doc.setFillColor(...grayLight);
        doc.rect(margin, y, tableW, rowH, 'F');
      }
      // separator line
      doc.setDrawColor(...grayLight);
      doc.setLineWidth(0.2);
      doc.line(margin, y+rowH, margin+tableW, y+rowH);

      cx = margin;
      doc.setTextColor(...dark);

      const vals = [
        {v: i+1, align:'center'},
        {v: descLines, align:'left', isLines:true},
        {v: row.tipo||'', align:'center'},
        {v: row.cantidad||'', align:'center'},
        {v: row.precioUnitario ? fmtCLP(row.precioUnitario) : '', align:'right'},
      ];

      vals.forEach((val, vi) => {
        const colW = cols[vi].w;
        if (val.isLines) {
          // draw multiple lines for description
          for (let li = 0; li < val.v.length; li++) {
            const textLine = val.v[li] || '';
            const ty = y + 3 + li * lineH;
            doc.text(textLine, cx + 2, ty);
          }
        } else {
          const text = String(val.v);
          if (val.align === 'center') {
            doc.text(text, cx + colW/2, y + rowH/2 + 1, {align:'center'});
          } else if (val.align === 'right') {
            doc.text(text, cx + colW - 2, y + rowH/2 + 1, {align:'right'});
          } else {
            doc.text(text, cx + 2, y + rowH/2 + 1);
          }
        }
        cx += colW;
      });

      // Vertical borders
      cx = margin;
      doc.setDrawColor(...grayLight);
      doc.setLineWidth(0.15);
      cols.forEach(col => {
        doc.line(cx, y, cx, y+rowH);
        cx += col.w;
      });
      doc.line(cx, y, cx, y+rowH);

      y += rowH;
      tableBodyHeight += rowH;
    });

    // Table border (include header height 10)
    doc.setDrawColor(...brown);
    doc.setLineWidth(0.5);
    doc.rect(margin, tableTop, tableW, tableBodyHeight + 10, 'S');

    y += 10;

    // ── RESUMEN ──
    doc.setFillColor(...brown);
    doc.rect(margin, y, tableW, 8, 'F');
    doc.setTextColor(...white);
    doc.setFontSize(9);
    doc.setFont('helvetica','bold');
    doc.text('RESUMEN DE COTIZACIÓN', W/2, y+5.5, {align:'center'});
    y += 12;

    const allRows = getRows();
    
    // Contar productos por descripción (para descuentos)
    const productCounts2 = {};
    allRows.forEach(r => {
      const desc = r.desc || '';
      productCounts2[desc] = (productCounts2[desc] || 0) + r.cantidad;
    });
    
    let subProductosOriginal = 0, subProductos = 0, descuentoTotal2 = 0;
    allRows.forEach(r => {
      const totalProductos = productCounts2[r.desc || ''] || 0;
      const precioOriginal = r.precioUnitario * r.cantidad;
      subProductosOriginal += precioOriginal;
      
      let precioUnitario = r.precioUnitario;
      if (totalProductos >= 10) {
        precioUnitario = r.precioUnitario * 0.8; // Aplicar 20% descuento
        descuentoTotal2 += precioOriginal - (precioUnitario * r.cantidad);
      }
      subProductos += precioUnitario * r.cantidad;
    });
    
    const kitV = installState.kit ? (parseFloat(document.getElementById('kit_precio').value)||0) : 0;
    const coreV = installState.core ? (parseFloat(document.getElementById('core_precio').value)||0) : 0;
    const despV = installState.desp ? (parseFloat(document.getElementById('desp_precio').value)||0) : 0;
    const opcionalesTotal = kitV + coreV + despV;
    
    const totalFinal = subProductos + opcionalesTotal;

    // Resumen simplificado con descuentos
    doc.setFillColor(...cream);
    doc.setDrawColor(...brown);
    doc.setLineWidth(0.4);
    const resumenHeight = descuentoTotal2 > 0 ? 36 : 24;
    doc.roundedRect(margin, y, tableW, resumenHeight, 2, 2, 'FD');

    let items = [
      ['Subtotal original (s/ desc.):', fmtCLP(subProductosOriginal)],
    ];
    if (descuentoTotal2 > 0) {
      items.push(['Descuento por mayor (-20%):', '- ' + fmtCLP(descuentoTotal2)]);
    }
    items.push(['Subtotal Productos:', fmtCLP(subProductos)]);
    items.push(['Opcionales:', opcionalesTotal>0 ? fmtCLP(opcionalesTotal) : '—']);
    
    items.forEach((item, i) => {
      const iy = y + 5 + i * 7;
      doc.setFont('helvetica','normal');
      doc.setTextColor(...dark);
      doc.setFontSize(7);
      doc.text(item[0], margin + 3, iy);
      doc.setFont('helvetica','bold');
      if (item[0].includes('Descuento')) {
        doc.setTextColor(...gold); // rojo del tema (--gold)
      }
      doc.text(item[1], margin + tableW - 3, iy, {align:'right'});
    });

    y += resumenHeight + 8;

    // TOTAL
    doc.setFillColor(...brown);
    doc.setDrawColor(...brown);
    doc.roundedRect(margin, y, tableW, 10, 2, 2, 'FD');
    doc.setTextColor(...white);
    doc.setFontSize(8);
    doc.setFont('helvetica','bold');
    doc.text('TOTAL COTIZACIÓN:', margin+3, y+4.5);
    doc.setTextColor(...goldLight);
    doc.setFontSize(12);
    doc.text(fmtCLP(totalFinal), margin+tableW-3, y+6, {align:'right'});
    
    y += 16;

    // ── NOTAS ──
    doc.setFillColor(...cream);
    doc.setDrawColor(...brown);
    doc.setLineWidth(0.4);
    doc.roundedRect(margin, y, tableW, 36, 2, 2, 'FD');

    doc.setFontSize(7.5);
    doc.setFont('helvetica','bold');
    doc.setTextColor(...brown);
    doc.text('CONDICIONES Y NOTAS', margin+4, y+6);

    const notas = [
      'Cotización válida por 15 días hábiles desde la fecha de emisión.',
      'Valores en pesos chilenos (CLP). Precios no incluyen IVA salvo indicación expresa.',
      'Diseño y arte adicional tienen costo extra.',
      'Colores disponibles: consultar con equipo de producción.',
      'Menarquita verifica calidad de producción antes de envío.',
      'Garantía de 12 meses contra defectos de impresión.',
    ];
    doc.setFont('helvetica','normal');
    doc.setTextColor(...dark);
    doc.setFontSize(6.5);
    // Actualizar notas en PDF
    const notasPDF = [
      'Cotización válida por 15 días hábiles desde la fecha de emisión.',
      'Valores en pesos chilenos (CLP). Precios no incluyen IVA salvo indicación expresa.',
      'Diseño y arte adicional tienen costo extra.',
      'Colores disponibles: consultar con equipo de producción.',
      'Menarquita verifica calidad de producción antes de envío.',
      'Garantía de 12 meses contra defectos de impresión.',
    ];
    notasPDF.forEach((nota, i) => {
      doc.text('• ' + nota, margin+4, y+12+i*4);
    });

    y += 40;

    // ── FOOTER ──
    doc.setFillColor(...brown);
    doc.rect(0, H-18, W, 18, 'F');
    doc.setTextColor(...white);
    doc.setFontSize(7);
    doc.setFont('helvetica','normal');
    doc.text('Menarquita — Objetos Sublimados de Calidad', W/2, H-12, {align:'center'});
    doc.text('info@menarquita.cl | +56 9 2870 6208 |  Talca, Chile', W/2, H-7, {align:'center'});
    doc.setTextColor(...goldLight);
    doc.setFont('helvetica','bold');
    doc.setFontSize(7);

    // Save
    const nombre = document.getElementById('nombre').value || 'cliente';
    const ncotVal = document.getElementById('ncotizacion').value || '001';
    doc.save(`Cotizacion_Menarquita_${ncotVal}_${nombre.replace(/[^a-zA-Z0-9]/g,'_')}.pdf`);

  } catch(err) {
    alert('Error al generar PDF: ' + err.message);
    console.error(err);
  }

  btn.innerHTML = '📄 Exportar PDF';
  btn.disabled = false;
}